// https://help.sumologic.com/Cloud_SIEM_Enterprise/Records%2C_Signals%2C_Entities%2C_and_Insights/15Searching_for_CSE_Records_in_Sumo_Logic
_index=sec_record_* // phase I _sourceCategory="asoc/RECORD/records"

// phase II have index so don't need json parsing
//| json field=_raw "metadata_product" as product nodrop
//| json field=_raw "metadata_vendor" as vendor nodrop
//| json field=_raw "metadata_mapperName" as mapper nodrop
//| json field=_raw "objectType" as type nodrop 
//| json field=_raw "objectClassification" as classification nodrop
//| json field=_raw "fields.reason" as reason nodrop

// phase II sec_record_* index
| metadata_product as product
| metadata_vendor as vendor
| metadata_mapperName as mapper
| metadata_parser as parser
| metadata_deviceEventId as deviceeventid
| objectType as type
| objectClassification as classification
| count by _view,vendor, product, mapper, parser,deviceeventid,type, classification | sort by vendor, _count
